25	const parseCookieHeader = (cookieHeader: string | null): Record<string, string> => {
26	    if (!cookieHeader) return {};
27	
28	    return cookieHeader.split(';').reduce<Record<string, string>>((acc, cookie) => {
29	        const trimmed = cookie.trim();
30	        if (!trimmed) return acc;
31	        const [name, ...rest] = trimmed.split('=');
32	        if (!name) return acc;
