57	 *  - `PLAYWRIGHT_TEST=true` is set (allows `next start` in production-build
58	 *    mode to honour mock-auth cookies during CI Playwright runs).
59	 */
60	export function isMockAuthEnabled(): boolean {
61	    return (
62	        process.env.NODE_ENV === 'development' ||
63	        process.env.NODE_ENV === 'test' ||
64	        process.env.PLAYWRIGHT_TEST === 'true'
65	    );
66	}
