76	 * absent, invalid, or in production.
77	 */
78	export async function getMockAuthState(): Promise<AuthRole> {
79	    if (!isMockAuthEnabled()) {
80	        return 'none';
81	    }
82	
83	    const cookieHeader = (await headers()).get('cookie');
84	    const cookies = parseCookieHeader(cookieHeader);
85	    const value = cookies[MOCK_AUTH_COOKIE];
