30	/**
31	 * Converts date-like properties of a `UserWithRole` into ISO string
32	 * representations.
33	 *
34	 * @param user - The user object containing `createdAt`, `updatedAt`, and
35	 * optional `banExpires` fields.
36	 * @returns A `UserWithRolePayload` with `createdAt`, `updatedAt`, and
37	 * `banExpires` serialized to ISO strings, leaving `banExpires` as `null` when
38	 * absent.
39	 */
40	const serializeUserDates = (user: UserWithRole): UserWithRolePayload => ({
41	    ...user,
42	    createdAt: user.createdAt instanceof Date ? user.createdAt.toISOString() : new Date(user.createdAt).toISOString(),
43	    updatedAt: user.updatedAt instanceof Date ? user.updatedAt.toISOString() : new Date(user.updatedAt).toISOString(),
44	    banExpires: user.banExpires instanceof Date ?
45	        user.banExpires.toISOString() :
46	        user.banExpires ?
47	            new Date(user.banExpires).toISOString() :
48	            null,
49	});
50	
51	/**
52	 * Retrieves a list of users, optionally filtered by email.
53	 *
54	 * In mock admin mode, returns all users or filters them by email if provided.
55	 * In mock non-admin mode, returns an empty array. In production mode, fetches
56	 * users from the auth API with optional email search.
57	 *
58	 * @param email - Optional email address to filter users by (supports partial
59	 * matches)
60	 * @param deps - Authentication dependencies including auth API and mock state
61	 * handlers
62	 * @returns Promise resolving to an array of users with serialized dates
63	 */
64	export async function listUsersActionCore(
65	    email?: string,
66	    deps: AuthDeps = defaultDeps,
67	): Promise<UserWithRolePayload[]> {
68	    const mockState = await deps.getMockAuthState();
69	    if (mockState === 'admin') {
70	        const users = deps.getMockUsersList();
71	        if (!email) return users.map(serializeUserDates);
72	        const decodedEmail = decodeURIComponent(email);
73	        return users
74	            .filter((user) => user.email.toLowerCase().includes(decodedEmail.toLowerCase()))
75	            .map(serializeUserDates);
76	    }
77	    if (mockState !== 'none') {
78	        return [];
79	    }
80	
81	    const response = await deps.auth.api.listUsers({
82	        headers: await deps.headers(),
83	        query: email ?
84	            {
85	                searchField: 'email',
86	                searchOperator: 'contains',
87	                searchValue: decodeURIComponent(email),
88	            } :
89	            {
90	                limit: 10,
91	            },
92	    });
93	
94	    return (response?.users ?? []).map(serializeUserDates);
95	}
