97	/**
98	 * Sets the admin role for a user in the authentication system.
99	 *
100	 * @param userId - The ID of the user whose role should be set
101	 * @param isAdmin - Whether to set the user as an admin (true) or regular user
102	 * (false)
103	 * @param deps - Dependencies object containing auth API and utility functions
104	 * (defaults to defaultDeps)
105	 *
106	 * @throws {AuthError} If mock auth state is not `none` or `admin`.
107	 *
108	 * @returns A promise that resolves when the role has been successfully set
109	 *
110	 * @remarks
111	 * This function checks the mock auth state before proceeding:
112	 * - If state is 'admin', the operation is skipped
113	 * - If state is 'none', the operation proceeds
114	 * - Any other state results in a Forbidden error
115	 */
116	export async function setAdminRoleActionCore(
117	    userId: string,
118	    isAdmin: boolean,
119	    deps: AuthDeps = defaultDeps,
120	) {
121	    const mockState = await deps.getMockAuthState();
122	    if (mockState === 'admin') {
123	        return;
124	    }
125	    if (mockState !== 'none') {
126	        throw new AuthError('Forbidden');
127	    }
128	
129	    await deps.auth.api.setRole({
130	        headers: await deps.headers(),
131	        body: {
132	            userId: userId,
133	            role: isAdmin ? 'admin' : 'user',
134	        },
135	    });
136	}
