15	 * Resolves an anchor's href to a same-origin pathname, or null if it's
16	 * external, a fragment, or a non-navigational scheme (mailto:, tel:, etc.).
17	 * Query strings are stripped deliberately: pages like year-filtered tables
18	 * would otherwise combinatorially explode the crawl (one variant per year per
19	 * table), and the query-string dimension isn't what this crawl is checking -
20	 * it's checking that every distinct *page* (route + entity id) renders.
21	 */
22	const toSameOriginPathname = (href: string, origin: string): string | null => {
23	    if (/^(#|mailto:|tel:|javascript:)/i.test(href)) return null;
24	    let url: URL;
25	    try {
26	        url = new URL(href, origin);
27	    } catch {
28	        return null;
29	    }
30	    if (url.origin !== origin || url.pathname.startsWith('/api/')) return null;
31	    return url.pathname;
